// Authorization decision endpoint
app.post(
  '/authorize/decision',
  authRateLimiter,
  [
    body('client_id').isString().trim().isLength({ min: 1, max: 256 }),
    body('redirect_uri').isString().trim().isLength({ min: 1, max: 2048 }),
    body('scope').isString().trim().isLength({ max: 1024 }),
    body('state').isString().trim().isLength({ min: 8, max: 512 }),
    body('code_challenge').isString().trim().isLength({ min: 1, max: 512 }),
    body('code_challenge_method').equals('S256'),
    body('username').isString().trim().isLength({ min: 1, max: 256 }),
    body('password').isString().isLength({ min: 1, max: 1024 }),
    body('decision').isIn(['approve', 'deny']),
  ],
  async (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ error: 'invalid_request', details: errors.array() });
    }

    const { client_id, redirect_uri, scope, state, code_challenge, code_challenge_method, username, password, decision } = req.body;

    // Decode values that were encoded in the form
    const decodedRedirectUri = decodeURIComponent(redirect_uri);
    const decodedState = decodeURIComponent(state);
    const decodedCodeChallenge = decodeURIComponent(code_challenge);
    const decodedScope = decodeURIComponent(scope);

    // Re-validate client
    const client = REGISTERED_CLIENTS.get(client_id);
    if (!client) {
      return res.status(400).json({ error: 'invalid_client' });
    }

    // Re-validate redirect URI
    if (!validateRedirectUri(client, decodedRedirectUri)) {
      return res.status(400).json({ error: 'invalid_request', error_description: 'Invalid redirect_uri' });
    }

    // Build redirect URL
    const redirectUrl = new URL(decodedRedirectUri);

    if (decision === 'deny') {
      redirectUrl.searchParams.set('error', 'access_denied');
      redirectUrl.searchParams.set('state', decodedState);
      return res.redirect(303, redirectUrl.toString());
    }

    // Authenticate user
    const user = await authenticateUser(username, password);
    if (!user) {
      return res.status(401).send('Invalid credentials. <a href="javascript:history.back()">Try again</a>');
    }

    // Generate authorization code
    const authCode = generateAuthCode();
    const codeHash = hashToken(authCode);

    const codeMetadata = {
      client_id,
      user_id: user.user_id,
      redirect_uri: decodedRedirectUri,
      scope: decodedScope,
      code_challenge: decodedCodeChallenge,
      code_challenge_method: code_challenge_method,
      created_at: Date.now(),
    };

    await storeAuthCode(codeHash, codeMetadata);

    redirectUrl.searchParams.set('code', authCode);
    redirectUrl.searchParams.set('state', decodedState);

    res.redirect(303, redirectUrl.toString());
  }
);

