  if (!code || typeof code !== 'string' || code.length > 512) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'Missing or invalid code' });
  }

  if (!redirect_uri || typeof redirect_uri !== 'string') {
    return res.status(400).json({ error: 'invalid_request', error_description: 'Missing redirect_uri' });
  }

  if (!code_verifier || typeof code_verifier !== 'string' || code_verifier.length < 43 || code_verifier.length > 128) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'Missing or invalid code_verifier' });
  }

  const codeHash = hashToken(code);
  const codeMetadata = await consumeAuthCode(codeHash);

  if (!codeMetadata) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Invalid or expired authorization code' });
  }

  // Validate the code was issued to this client
  if (codeMetadata.client_id !== client.client_id) {
    return res.status(400).json({ error: 'invalid_grant' });
  }

  // Validate redirect_uri matches
  if (codeMetadata.redirect_uri !== redirect_uri) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'redirect_uri mismatch' });
  }

  // Validate PKCE
  const expectedChallenge = generateCodeChallenge(code_verifier);
  if (!crypto.timingSafeEqual(Buffer.from(expectedChallenge), Buffer.from(codeMetadata.code_challenge))) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'PKCE verification failed' });
  }

  // Issue tokens
  const accessToken = generateToken();
  const refreshToken = generateToken();
  const accessTokenHash = hashToken(accessToken);
  const refreshTokenHash = hashToken(refreshToken);

  const now = Date.now();

  const accessTokenMetadata = {
    client_id: client.client_id,
    user_id: codeMetadata.user_id,
    scope: codeMetadata.scope,
    created_at: now,
    expires_at: now + ACCESS_TOKEN_EXPIRY * 1000,
  };

  const refreshTokenMetadata = {
    client_id: client.client_id,
    user_id: codeMetadata.user_id,
    scope: codeMetadata.scope,
    created_at: now,
    expires_at: now + REFRESH_TOKEN_EXPIRY * 1000,
    use_count: 0,
    last_used_at: null,
    last_used_ip: null,
    token_family: crypto.randomUUID(), // For detecting token theft
  };

  await storeAccessToken(accessTokenHash, accessTokenMetadata);
  await storeRefreshToken(refreshTokenHash, refreshTokenMetadata);
  await trackUserToken(codeMetadata.user_id, refreshTokenHash);

